(8, 2, 'Capital Formation', 'How would you characterise the AI venture capital ecosystem in your country?', 'Minimal AI VC activity', 'Some AI VC deals but fragmented and below $500M total annually', 'Active AI VC ecosystem with $500M–$5B annually', 'Deep AI VC market with > $5B annually and domestic institutional LPs', null, 10, 35, 65, 95, null),
